const items = $input.all();
const output = [];

// execution_id e client_id vindos do workflow principal
const execution_id = $('Start').first().json.execution_id;
const client_id_filter = $('Start').first().json.client_id;

if (!execution_id) {
  throw new Error('execution_id não recebido do workflow principal');
}

for (const item of items) {
  const props = item.json.properties;

  // Status — apenas Em execução
  const status = props['Status']?.status?.name?.trim() || null;
  if (status !== 'Em execução') continue;

  // client_id
  const client_id = props['client_id']?.rich_text?.[0]?.plain_text?.trim() || null;
  if (!client_id) continue;

  // fonte e campaign_id — nomes corretos das propriedades do Notion
  const fonte = props['Fonte']?.multi_select?.[0]?.name?.trim() || null;
  const google_id_campaign  = props['id_google_camp']?.number ?? null;
  const campaign_id_google  = google_id_campaign ? `GADS-${google_id_campaign}` : null;
  const campaign_id_meta    = props['id_meta_camp']?.number
    ? `META-${props['id_meta_camp'].number}` : null;
  const campaign_id = fonte === 'Google Ads' ? campaign_id_google
    : fonte === 'Meta Ads' ? campaign_id_meta
    : null;

  if (!campaign_id) continue;

  // demais campos — nomes corretos das propriedades do Notion
  const campaign_name       = props['Nome da campanha']?.title?.[0]?.plain_text?.trim() || null;
  const customer_id_google  = props['id_google_account']?.number
    ? String(props['id_google_account'].number) : null;
  const pixel_id_meta       = props['id_meta_pixel']?.number
    ? String(props['id_meta_pixel'].number) : null;
  const primary_metric_type = props['Métrica-Mãe']?.multi_select?.[0]?.name?.trim() || 'ROAS';
  const primary_metric_goal = props['Meta da Métrica-mãe']?.number ?? null;

  output.push({
    json: {
      execution_id,
      client_id,
      campaign_name,
      campaign_id,
      fonte,
      customer_id_google,
      pixel_id_meta,
      primary_metric_type,
      primary_metric_goal,
      google_id_campaign,
    }
  });
}

return output;

