const item = $input.first().json;
const result = item.results?.[0];

if (!result) {
  throw new Error('Google Ads API não retornou resultados');
}

const metrics = result.metrics;

// Recuperar dados da campanha do node anterior
const campaignData = $('Edit Fields').first().json;

return [{
  json: {
    execution_id:         campaignData.execution_id,
    client_id:            campaignData.client_id,
    campaign_id:          campaignData.campaign_id,
    campaign_name:        campaignData.campaign_name,
    primary_metric_type:  campaignData.primary_metric_type,
    primary_metric_goal:  campaignData.primary_metric_goal,
    fonte:                campaignData.fonte,
    impressions:          parseInt(metrics.impressions || 0),
    clicks:               parseInt(metrics.clicks || 0),
    cost:                 parseFloat((parseInt(metrics.costMicros || 0) / 1000000).toFixed(2)),
    conversions:          parseInt(metrics.conversions || 0),
    revenue:              parseFloat(metrics.conversionsValue || 0),
  }
}];
